macroData.command:
// BENIGN TRANSPOSITION — TELEPORT SELF
// Midi-QOL On Use pass: preItemRoll

const REQUIRED_PASS = "preItemRoll";
if (args?.[0]?.macroPass && args[0].macroPass !== REQUIRED_PASS) return;

const data = args?.[0] ?? {};
const workflow =
  data.workflow ??
  MidiQOL.Workflow?.getWorkflow?.(data.uuid);

const source =
  workflow?.token ??
  canvas.tokens.get(data.tokenId) ??
  canvas.tokens.controlled[0];

if (!source) {
  ui.notifications.warn(
    "Benign Transposition: no source token was found."
  );
  return false;
}

const grid = canvas.grid;

if (!grid?.isSquare) {
  ui.notifications.warn(
    "Benign Transposition: this picker requires a square grid."
  );
  return false;
}

const gridLayer = foundry.canvas.layers.GridLayer.instance;

const sx = grid.sizeX;
const sy = grid.sizeY;
const gridDistance = grid.distance;

const units = String(
  grid.units ??
  canvas.scene.grid.units ??
  "ft"
).trim().toLowerCase();

const metric =
  /^(m|meter|meters|metre|metres)$/.test(units);

const RANGE = metric ? 9.144 : 30;
const RANGE_LABEL = metric ? "9.144 m" : "30 ft";

const logicalW = Number(source.document.width ?? 1);
const logicalH = Number(source.document.height ?? 1);

const cellsW = Math.max(1, Math.ceil(logicalW));
const cellsH = Math.max(1, Math.ceil(logicalH));

const pixelW = logicalW * sx;
const pixelH = logicalH * sy;

const sourceElevation =
  Number(source.document.elevation ?? 0);

const origin = grid.getTopLeftPoint({
  x: Number(source.document.x) + 1,
  y: Number(source.document.y) + 1
});

const sceneRect =
  canvas.dimensions.sceneRect ?? {
    x: canvas.dimensions.sceneX,
    y: canvas.dimensions.sceneY,
    width: canvas.dimensions.sceneWidth,
    height: canvas.dimensions.sceneHeight
  };

/* -------------------------------------------- */
/* Utility functions                            */
/* -------------------------------------------- */

function key(x, y) {
  return `${Math.round(x)},${Math.round(y)}`;
}

function footprintCenters(anchorX, anchorY) {
  const points = [];

  for (let col = 0; col < cellsW; col++) {
    for (let row = 0; row < cellsH; row++) {
      points.push(
        grid.getCenterPoint({
          x: anchorX + (col + 0.5) * sx,
          y: anchorY + (row + 0.5) * sy
        })
      );
    }
  }

  return points;
}

const originCells =
  footprintCenters(origin.x, origin.y);

function gridDistanceTo(anchorX, anchorY) {
  let best = Infinity;

  const destinationCells =
    footprintCenters(anchorX, anchorY);

  for (const originPoint of originCells) {
    for (const destinationPoint of destinationCells) {
      const measured = grid.measurePath([
        originPoint,
        destinationPoint
      ]);

      best = Math.min(
        best,
        Number(measured.distance)
      );
    }
  }

  return best;
}

function withinScene(anchorX, anchorY) {
  const right =
    sceneRect.x + sceneRect.width;

  const bottom =
    sceneRect.y + sceneRect.height;

  return (
    anchorX >= sceneRect.x &&
    anchorY >= sceneRect.y &&
    anchorX + pixelW <= right &&
    anchorY + pixelH <= bottom
  );
}

function rectsOverlap(a, b) {
  const epsilon = 0.5;

  return (
    a.x < b.x + b.w - epsilon &&
    a.x + a.w > b.x + epsilon &&
    a.y < b.y + b.h - epsilon &&
    a.y + a.h > b.y + epsilon
  );
}

function verticalBounds(
  token,
  elevationOverride
) {
  const bottom = Number(
    elevationOverride ??
    token.document.elevation ??
    0
  );

  /*
   * Foundry does not provide a universal token-height
   * property. This uses the larger token dimension as
   * a reasonable vertical occupancy estimate.
   */
  const estimatedHeight =
    Math.max(
      Number(token.document.width ?? 1),
      Number(token.document.height ?? 1)
    ) * gridDistance;

  return {
    bottom,
    top: bottom + estimatedHeight
  };
}

function verticalOverlap(a, b) {
  return (
    a.bottom < b.top &&
    a.top > b.bottom
  );
}

function isOccupied(anchorX, anchorY) {
  const destinationRect = {
    x: anchorX,
    y: anchorY,
    w: pixelW,
    h: pixelH
  };

  const destinationZ =
    verticalBounds(
      source,
      sourceElevation
    );

  return canvas.tokens.placeables.some(other => {
    if (other.id === source.id) return false;

    const otherRect = {
      x: Number(other.document.x),
      y: Number(other.document.y),

      w:
        Number(other.document.width ?? 1) *
        sx,

      h:
        Number(other.document.height ?? 1) *
        sy
    };

    return (
      rectsOverlap(
        destinationRect,
        otherRect
      ) &&
      verticalOverlap(
        destinationZ,
        verticalBounds(other)
      )
    );
  });
}

function canSeePoint(point) {
  if (!canvas.scene.tokenVision) {
    return true;
  }

  /*
   * Check the caster's own vision polygon rather than
   * merely relying on GM omniscience.
   */
  const polygon =
    source.vision?.fov ??
    source.vision?.los;

  if (
    polygon?.contains &&
    !polygon.contains(point.x, point.y)
  ) {
    return false;
  }

  /*
   * For players, also require Foundry to consider the
   * point currently visible.
   */
  if (!game.user.isGM) {
    return canvas.visibility.testVisibility(
      point,
      { tolerance: 2 }
    );
  }

  return true;
}

function destinationVisible(
  anchorX,
  anchorY
) {
  return footprintCenters(
    anchorX,
    anchorY
  ).every(canSeePoint);
}

/* -------------------------------------------- */
/* Proper teleport                              */
/* -------------------------------------------- */

async function properTeleport(
  token,
  center,
  elevation
) {
  const destination = {
    x: Number(center.x),
    y: Number(center.y),
    elevation: Number(elevation)
  };

  /*
   * Preferred API on current Midi-QOL v13.
   */
  if (
    typeof MidiQOL.teleportToken ===
    "function"
  ) {
    return MidiQOL.teleportToken(
      token,
      destination
    );
  }

  /*
   * Compatibility fallback for older Midi-QOL
   * v13 installations.
   */
  const socket = MidiQOL.socket?.();

  if (socket?.executeAsGM) {
    try {
      return await socket.executeAsGM(
        "moveToken",
        {
          tokenUuid: token.document.uuid,

          newCenter: destination,

          options: {
            teleport: true,
            animate: false,
            ignoreWalls: true,
            ignoreTokens: true
          }
        }
      );
    } catch (error) {
      console.warn(
        "Benign Transposition | " +
        "Midi-QOL GM move fallback failed",
        error
      );
    }
  }

  /*
   * Last-resort direct update. This works for a GM
   * or a token owned by the executing user.
   */
  if (
    !game.user.isGM &&
    !token.document.isOwner
  ) {
    throw new Error(
      "No GM-mediated teleport API is " +
      "available for this token."
    );
  }

  return token.document.update(
    {
      x:
        destination.x -
        (
          Number(
            token.document.width ?? 1
          ) * sx
        ) / 2,

      y:
        destination.y -
        (
          Number(
            token.document.height ?? 1
          ) * sy
        ) / 2,

      elevation:
        destination.elevation
    },
    {
      animate: false,
      teleport: true
    }
  );
}

/* -------------------------------------------- */
/* Calculate every legal destination            */
/* -------------------------------------------- */

const candidates = new Map();

const stepRadius =
  Math.ceil(RANGE / gridDistance) +
  Math.max(cellsW, cellsH) +
  1;

for (
  let dx = -stepRadius;
  dx <= stepRadius;
  dx++
) {
  for (
    let dy = -stepRadius;
    dy <= stepRadius;
    dy++
  ) {
    const x = origin.x + dx * sx;
    const y = origin.y + dy * sy;

    /*
     * Do not permit the token to teleport to its
     * existing square.
     */
    if (
      Math.abs(x - origin.x) < 0.5 &&
      Math.abs(y - origin.y) < 0.5
    ) {
      continue;
    }

    if (!withinScene(x, y)) continue;

    const distance =
      gridDistanceTo(x, y);

    if (
      !Number.isFinite(distance) ||
      distance > RANGE + 0.001
    ) {
      continue;
    }

    if (isOccupied(x, y)) continue;

    if (
      !destinationVisible(x, y)
    ) {
      continue;
    }

    candidates.set(
      key(x, y),
      {
        x,
        y,
        distance,

        center: {
          x: x + pixelW / 2,
          y: y + pixelH / 2
        }
      }
    );
  }
}

if (!candidates.size) {
  ui.notifications.warn(
    "Benign Transposition: no legal " +
    `destination exists within ${RANGE_LABEL}.`
  );

  return false;
}

/* -------------------------------------------- */
/* Interactive grid picker                      */
/* -------------------------------------------- */

async function chooseDestination() {
  const id =
    foundry.utils.randomID();

  const rangeLayer =
    `benign-range-${id}`;

  const hoverLayer =
    `benign-hover-${id}`;

  gridLayer.addHighlightLayer(
    rangeLayer
  );

  gridLayer.addHighlightLayer(
    hoverLayer
  );

  /*
   * Green cells are legal top-left token anchors.
   */
  for (
    const candidate of
    candidates.values()
  ) {
    gridLayer.highlightPosition(
      rangeLayer,
      {
        x: candidate.x + sx / 2,
        y: candidate.y + sy / 2,

        color: 0x33ff99,
        border: 0x0d8a5f,
        alpha: 0.22
      }
    );
  }

  const view =
    canvas.app.canvas ??
    canvas.app.view;

  const oldCursor =
    view?.style?.cursor ?? "";

  if (view?.style) {
    view.style.cursor = "crosshair";
  }

  ui.notifications.info(
    "Benign Transposition: click a green " +
    `grid space within ${RANGE_LABEL}. ` +
    "Right-click or press Esc to cancel."
  );

  return new Promise(resolve => {
    let current = null;

    const cleanup = () => {
      canvas.stage.off(
        "pointermove",
        onMove
      );

      canvas.stage.off(
        "pointerdown",
        onDown
      );

      window.removeEventListener(
        "keydown",
        onKey,
        true
      );

      view?.removeEventListener?.(
        "contextmenu",
        blockContextMenu
      );

      gridLayer.destroyHighlightLayer(
        rangeLayer
      );

      gridLayer.destroyHighlightLayer(
        hoverLayer
      );

      if (view?.style) {
        view.style.cursor = oldCursor;
      }
    };

    const finish = result => {
      cleanup();
      resolve(result);
    };

    const eventPoint = event =>
      canvas.stage.toLocal(
        event.global
      );

    const drawFootprint = (
      anchorX,
      anchorY,
      valid
    ) => {
      gridLayer.clearHighlightLayer(
        hoverLayer
      );

      const color = valid
        ? 0x63ffb5
        : 0xff3b5c;

      const border = valid
        ? 0xffffff
        : 0x7f0017;

      for (
        const point of
        footprintCenters(
          anchorX,
          anchorY
        )
      ) {
        gridLayer.highlightPosition(
          hoverLayer,
          {
            x: point.x,
            y: point.y,
            color,
            border,
            alpha: 0.45
          }
        );
      }
    };

    const onMove = event => {
      const point =
        eventPoint(event);

      const anchor =
        grid.getTopLeftPoint(point);

      current =
        candidates.get(
          key(anchor.x, anchor.y)
        ) ?? null;

      drawFootprint(
        anchor.x,
        anchor.y,
        Boolean(current)
      );
    };

    const onDown = event => {
      const button =
        event.button ??
        event.nativeEvent?.button ??
        0;

      event.stopPropagation?.();
      event.nativeEvent
        ?.preventDefault?.();

      if (button === 2) {
        return finish(null);
      }

      if (button !== 0) return;

      if (!current) {
        ui.notifications.warn(
          "Benign Transposition: that is " +
          "not a legal destination."
        );

        return;
      }

      finish(current);
    };

    const onKey = event => {
      if (event.key !== "Escape") {
        return;
      }

      event.preventDefault();
      finish(null);
    };

    const blockContextMenu =
      event => event.preventDefault();

    canvas.stage.on(
      "pointermove",
      onMove
    );

    canvas.stage.on(
      "pointerdown",
      onDown
    );

    window.addEventListener(
      "keydown",
      onKey,
      true
    );

    view?.addEventListener?.(
      "contextmenu",
      blockContextMenu
    );
  });
}

/* -------------------------------------------- */
/* Execute                                      */
/* -------------------------------------------- */

const selected =
  await chooseDestination();

if (!selected) return false;

try {
  await properTeleport(
    source,
    selected.center,
    sourceElevation
  );

  return true;
} catch (error) {
  console.error(
    "Benign Transposition | " +
    "Teleport Self failed",
    error
  );

  ui.notifications.error(
    "Benign Transposition failed: " +
    error.message
  );

  return false;
}

// BENIGN TRANSPOSITION — SWAP
// Midi-QOL On Use pass: preItemRoll

const REQUIRED_PASS = "preItemRoll";
if (
  args?.[0]?.macroPass &&
  args[0].macroPass !== REQUIRED_PASS
) {
  return;
}

const data = args?.[0] ?? {};

const workflow =
  data.workflow ??
  MidiQOL.Workflow?.getWorkflow?.(
    data.uuid
  );

const source =
  workflow?.token ??
  canvas.tokens.get(data.tokenId) ??
  canvas.tokens.controlled[0];

if (!source) {
  ui.notifications.warn(
    "Benign Transposition: no source " +
    "token was found."
  );

  return false;
}

/* -------------------------------------------- */
/* Resolve selected target                      */
/* -------------------------------------------- */

const rawTargets =
  workflow?.targets
    ? Array.from(workflow.targets)
    : data.targets
      ? Array.from(data.targets)
      : Array.from(
          game.user.targets ?? []
        );

const targets = rawTargets
  .map(target =>
    target?.object ?? target
  )
  .filter(Boolean)
  .filter(target =>
    target.id !== source.id
  );

if (targets.length !== 1) {
  ui.notifications.warn(
    "Benign Transposition: target " +
    "exactly one other creature."
  );

  return false;
}

const target = targets[0];

/* -------------------------------------------- */
/* Size validation                              */
/* -------------------------------------------- */

const size = String(
  target.actor?.system?.traits?.size ??
  ""
).toLowerCase();

const permittedSizes =
  new Set([
    "tiny",
    "sm",
    "med"
  ]);

if (
  size &&
  !permittedSizes.has(size)
) {
  ui.notifications.warn(
    "Benign Transposition: the target " +
    "must be Medium or smaller."
  );

  return false;
}

/* -------------------------------------------- */
/* Grid and range                               */
/* -------------------------------------------- */

const grid = canvas.grid;

if (!grid?.isSquare) {
  ui.notifications.warn(
    "Benign Transposition: this swap " +
    "requires a square grid."
  );

  return false;
}

const sx = grid.sizeX;
const sy = grid.sizeY;
const gridDistance = grid.distance;

const units = String(
  grid.units ??
  canvas.scene.grid.units ??
  "ft"
).trim().toLowerCase();

const metric =
  /^(m|meter|meters|metre|metres)$/.test(
    units
  );

const RANGE = metric ? 9.144 : 30;
const RANGE_LABEL =
  metric ? "9.144 m" : "30 ft";

function snappedAnchor(token) {
  return grid.getTopLeftPoint({
    x: Number(token.document.x) + 1,
    y: Number(token.document.y) + 1
  });
}

function footprintCenters(
  token,
  anchor = snappedAnchor(token)
) {
  const cellsW = Math.max(
    1,
    Math.ceil(
      Number(
        token.document.width ?? 1
      )
    )
  );

  const cellsH = Math.max(
    1,
    Math.ceil(
      Number(
        token.document.height ?? 1
      )
    )
  );

  const points = [];

  for (
    let col = 0;
    col < cellsW;
    col++
  ) {
    for (
      let row = 0;
      row < cellsH;
      row++
    ) {
      points.push(
        grid.getCenterPoint({
          x:
            anchor.x +
            (col + 0.5) * sx,

          y:
            anchor.y +
            (row + 0.5) * sy
        })
      );
    }
  }

  return points;
}

function edgeToEdgeDistance(a, b) {
  let best = Infinity;

  for (
    const pointA of
    footprintCenters(a)
  ) {
    for (
      const pointB of
      footprintCenters(b)
    ) {
      best = Math.min(
        best,
        Number(
          grid.measurePath([
            pointA,
            pointB
          ]).distance
        )
      );
    }
  }

  return best;
}

/*
 * Midi-QOL handles token footprints and
 * elevation when its distance API is present.
 */
const distance =
  typeof MidiQOL.computeDistance ===
  "function"
    ? Number(
        MidiQOL.computeDistance(
          source,
          target,
          {
            wallsBlock: false,
            includeElevation: true
          }
        )
      )
    : edgeToEdgeDistance(
        source,
        target
      );

if (
  !Number.isFinite(distance) ||
  distance < 0 ||
  distance > RANGE + 0.001
) {
  ui.notifications.warn(
    "Benign Transposition: the target " +
    `must be within ${RANGE_LABEL}.`
  );

  return false;
}

/* -------------------------------------------- */
/* Construct the two destinations               */
/* -------------------------------------------- */

const sourceOrigin =
  snappedAnchor(source);

const targetOrigin =
  snappedAnchor(target);

const sourceElevation =
  Number(
    source.document.elevation ?? 0
  );

const targetElevation =
  Number(
    target.document.elevation ?? 0
  );

/*
 * This is a genuine swap:
 *
 * Source takes the target's X/Y and elevation.
 * Target takes the source's X/Y and elevation.
 *
 * Neither elevation is discarded or reset to 0.
 */
const sourceDestination = {
  anchor: targetOrigin,
  elevation: targetElevation,

  center: {
    x:
      targetOrigin.x +
      Number(
        source.document.width ?? 1
      ) * sx / 2,

    y:
      targetOrigin.y +
      Number(
        source.document.height ?? 1
      ) * sy / 2
  }
};

const targetDestination = {
  anchor: sourceOrigin,
  elevation: sourceElevation,

  center: {
    x:
      sourceOrigin.x +
      Number(
        target.document.width ?? 1
      ) * sx / 2,

    y:
      sourceOrigin.y +
      Number(
        target.document.height ?? 1
      ) * sy / 2
  }
};

/* -------------------------------------------- */
/* Destination validation                       */
/* -------------------------------------------- */

const sceneRect =
  canvas.dimensions.sceneRect ?? {
    x: canvas.dimensions.sceneX,
    y: canvas.dimensions.sceneY,
    width: canvas.dimensions.sceneWidth,
    height: canvas.dimensions.sceneHeight
  };

function tokenRectAt(
  token,
  anchor
) {
  return {
    x: anchor.x,
    y: anchor.y,

    w:
      Number(
        token.document.width ?? 1
      ) * sx,

    h:
      Number(
        token.document.height ?? 1
      ) * sy
  };
}

function withinScene(rect) {
  return (
    rect.x >= sceneRect.x &&
    rect.y >= sceneRect.y &&

    rect.x + rect.w <=
      sceneRect.x +
      sceneRect.width &&

    rect.y + rect.h <=
      sceneRect.y +
      sceneRect.height
  );
}

function rectsOverlap(a, b) {
  const epsilon = 0.5;

  return (
    a.x < b.x + b.w - epsilon &&
    a.x + a.w > b.x + epsilon &&
    a.y < b.y + b.h - epsilon &&
    a.y + a.h > b.y + epsilon
  );
}

function verticalBounds(
  token,
  elevation
) {
  const bottom =
    Number(elevation);

  const estimatedHeight =
    Math.max(
      Number(
        token.document.width ?? 1
      ),

      Number(
        token.document.height ?? 1
      )
    ) * gridDistance;

  return {
    bottom,
    top:
      bottom +
      estimatedHeight
  };
}

function verticalOverlap(a, b) {
  return (
    a.bottom < b.top &&
    a.top > b.bottom
  );
}

const sourceFinalRect =
  tokenRectAt(
    source,
    sourceDestination.anchor
  );

const targetFinalRect =
  tokenRectAt(
    target,
    targetDestination.anchor
  );

if (
  !withinScene(sourceFinalRect) ||
  !withinScene(targetFinalRect)
) {
  ui.notifications.warn(
    "Benign Transposition: one of the " +
    "swapped tokens would leave the " +
    "scene bounds."
  );

  return false;
}

/*
 * This matters when creatures of different
 * token sizes swap adjacent spaces.
 */
if (
  rectsOverlap(
    sourceFinalRect,
    targetFinalRect
  ) &&
  verticalOverlap(
    verticalBounds(
      source,
      sourceDestination.elevation
    ),

    verticalBounds(
      target,
      targetDestination.elevation
    )
  )
) {
  ui.notifications.warn(
    "Benign Transposition: the final " +
    "token footprints would overlap."
  );

  return false;
}

function destinationBlocked(
  movingToken,
  destination,
  destinationRect
) {
  const ignored =
    new Set([
      source.id,
      target.id
    ]);

  const movingZ =
    verticalBounds(
      movingToken,
      destination.elevation
    );

  return canvas.tokens.placeables.some(
    other => {
      if (ignored.has(other.id)) {
        return false;
      }

      const otherRect =
        tokenRectAt(
          other,
          {
            x:
              Number(
                other.document.x
              ),

            y:
              Number(
                other.document.y
              )
          }
        );

      return (
        rectsOverlap(
          destinationRect,
          otherRect
        ) &&

        verticalOverlap(
          movingZ,

          verticalBounds(
            other,
            Number(
              other.document.elevation ??
              0
            )
          )
        )
      );
    }
  );
}

if (
  destinationBlocked(
    source,
    sourceDestination,
    sourceFinalRect
  ) ||

  destinationBlocked(
    target,
    targetDestination,
    targetFinalRect
  )
) {
  ui.notifications.warn(
    "Benign Transposition: one of the " +
    "destination spaces is occupied."
  );

  return false;
}

/* -------------------------------------------- */
/* Proper teleport helper                       */
/* -------------------------------------------- */

async function properTeleport(
  token,
  center,
  elevation
) {
  const destination = {
    x: Number(center.x),
    y: Number(center.y),
    elevation: Number(elevation)
  };

  if (
    typeof MidiQOL.teleportToken ===
    "function"
  ) {
    return MidiQOL.teleportToken(
      token,
      destination
    );
  }

  const socket =
    MidiQOL.socket?.();

  if (socket?.executeAsGM) {
    try {
      return await socket.executeAsGM(
        "moveToken",
        {
          tokenUuid:
            token.document.uuid,

          newCenter:
            destination,

          options: {
            teleport: true,
            animate: false,
            ignoreWalls: true,
            ignoreTokens: true
          }
        }
      );
    } catch (error) {
      console.warn(
        "Benign Transposition | " +
        "Midi-QOL GM move fallback failed",
        error
      );
    }
  }

  if (
    !game.user.isGM &&
    !token.document.isOwner
  ) {
    throw new Error(
      "No GM-mediated teleport API is " +
      "available for one of the tokens."
    );
  }

  return token.document.update(
    {
      x:
        destination.x -
        Number(
          token.document.width ?? 1
        ) * sx / 2,

      y:
        destination.y -
        Number(
          token.document.height ?? 1
        ) * sy / 2,

      elevation:
        destination.elevation
    },
    {
      animate: false,
      teleport: true
    }
  );
}

/* -------------------------------------------- */
/* Preserve original positions for rollback     */
/* -------------------------------------------- */

const sourceOriginalCenter = {
  x:
    sourceOrigin.x +
    Number(
      source.document.width ?? 1
    ) * sx / 2,

  y:
    sourceOrigin.y +
    Number(
      source.document.height ?? 1
    ) * sy / 2
};

const targetOriginalCenter = {
  x:
    targetOrigin.x +
    Number(
      target.document.width ?? 1
    ) * sx / 2,

  y:
    targetOrigin.y +
    Number(
      target.document.height ?? 1
    ) * sy / 2
};

/* -------------------------------------------- */
/* Execute both teleports                       */
/* -------------------------------------------- */

try {
  await Promise.all([
    properTeleport(
      source,
      sourceDestination.center,
      sourceDestination.elevation
    ),

    properTeleport(
      target,
      targetDestination.center,
      targetDestination.elevation
    )
  ]);

  return true;
} catch (error) {
  console.error(
    "Benign Transposition | Swap failed",
    error
  );

  /*
   * Best-effort rollback if one teleport
   * succeeded and the other failed.
   */
  await Promise.allSettled([
    properTeleport(
      source,
      sourceOriginalCenter,
      sourceElevation
    ),

    properTeleport(
      target,
      targetOriginalCenter,
      targetElevation
    )
  ]);

  ui.notifications.error(
    "Benign Transposition failed: " +
    error.message
  );

  return false;
}
